import time
from prometheus_client import Counter, generate_latest, REGISTRY
from flask import Flask, request, Response
import threading

app = Flask(__name__)

# Dictionary to store metrics for each unique user-path combination
metrics_cache = {}
metrics_lock = threading.Lock()

def get_or_create_metric(user_id, path):
    """Get or create a Counter metric for a specific user-path combination"""
    metric_key = f"user_{user_id}_path_{path.replace('/', '_').replace('-', '_').strip('_')}"
    
    # Sanitize metric name to comply with Prometheus naming conventions
    metric_key = ''.join(c if c.isalnum() or c == '_' else '_' for c in metric_key)
    metric_key = f"http_requests_{metric_key}"
    
    with metrics_lock:
        if metric_key not in metrics_cache:
            # Create a new counter for this user-path combination
            metrics_cache[metric_key] = Counter(
                metric_key,
                f'HTTP requests for user {user_id} on path {path}',
                ['user_id', 'session_id', 'path', 'method', 'status_code']
            )
    
    return metrics_cache[metric_key]

# General request counter with labels
http_requests_total = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['user_id', 'session_id', 'path', 'method', 'status_code']
)

@app.before_request
def before_request():
    request.start_time = time.time()

@app.after_request
def after_request(response):
    # Extract user_id and session_id from headers or query params
    user_id = request.headers.get('X-User-Id', request.args.get('user_id', 'anonymous'))
    session_id = request.headers.get('X-Session-Id', request.args.get('session_id', 'no_session'))
    path = request.path
    method = request.method
    status_code = str(response.status_code)
    
    # Increment general counter
    http_requests_total.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method,
        status_code=status_code
    ).inc()
    
    # Get or create specific metric for this user-path combination
    specific_metric = get_or_create_metric(user_id, path)
    specific_metric.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method,
        status_code=status_code
    ).inc()
    
    return response

@app.route('/metrics')
def metrics():
    """Prometheus metrics endpoint"""
    return Response(generate_latest(REGISTRY), mimetype='text/plain')

